"const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, '../src/data/units5.tsx');
const content = fs.readFileSync(filePath, 'utf8');

// Split the file by `unitNumber:` to isolate Units 1 to 8
const units = content.split(/unitNumber:\s*/g);

for (let i = 1; i <= 8; i++) {
  const unitBlock = units.find(u => u.trim().startsWith(String(i)));
  if (!unitBlock) {
    console.log(`Unit ${i} not found!`);
    continue;
  }

  console.log(`==================== UNIT ${i} ====================`);

  // Extract and print scoring labels (e.g. text containing "ຄະແນນ" or similar)
  console.log('--- Scoring Labels / Points ---');
  const scoringRegex = /"[^"]*ຄະແນນ[^"]*"/g;
  let match;
  while ((match = scoringRegex.exec(unitBlock)) !== null) {
    console.log(match[0]);
  }

  // Extract and print keyPoints section
  console.log('--- KeyPoints ---');
  const keyPointsStart = unitBlock.indexOf('keyPoints:');
  if (keyPointsStart !== -1) {
    // Find matching bracket for keyPoints
    let bracketCount = 0;
    let index = keyPointsStart;
    let keyPointsText = '';
    while (index < unitBlock.length) {
      const char = unitBlock[index];
      keyPointsText += char;
      if (char === '[') bracketCount++;
      else if (char === ']') {
        bracketCount--;
        if (bracketCount === 0) break;
      }
      index++;
    }
    console.log(keyPointsText);
  } else {
    console.log('No keyPoints found!');
  }
}
